const raw = $input.first().json;
const event = raw.body ?? raw;
const d = event.d ?? event;

// Reaction event
if (event.t === 'MESSAGE_REACTION_ADD') {
  const emoji = d.emoji?.name;
  const actionMap = { '✅': 'approve', '✏️': 'edit', '❌': 'reject' };
  const action = actionMap[emoji];
  if (!action) return [{ json: { skip: true } }];
  return [{ json: {
    skip: false,
    eventType: 'reaction',
    action,
    message_id: d.message_id,
    actor_discord_id: d.user_id,
    channel_id: d.channel_id
  }}];
}

// Text message event
if (event.t === 'MESSAGE_CREATE' || event.type === 0) {
  const referenced_id = d.referenced_message?.id ?? null;
  const content = (d.content ?? '').trim();
  const discord_id = d.author?.id;
  const channel_id = d.channel_id;

  // Thread-reply (edit flow) — must check before F-06 command detection
  if (referenced_id) {
    return [{ json: {
      skip: false,
      eventType: 'message',
      action: 'edit_reply',
      message_id: referenced_id,
      reply_id: d.id,
      actor_discord_id: discord_id,
      channel_id,
      content
    }}];
  }

  // F-06 fixed command detection — plain DM with no referenced message
  const FIXED_COMMANDS = ['yes', 'no', 'colleague', 'meeting', 'just-talk'];
  const lower = content.toLowerCase();

  if (lower === 'yes') {
    return [{ json: {
      skip: false,
      eventType: 'f06_command',
      action: 'unblock_yes',
      raw_action: 'unblock_yes',
      discord_id,
      channel_id,
      content
    }}];
  }

  if (lower === 'no') {
    return [{ json: {
      skip: false,
      eventType: 'f06_command',
      action: 'unblock_no',
      raw_action: 'unblock_no',
      discord_id,
      channel_id,
      content
    }}];
  }

  if (lower === 'colleague') {
    return [{ json: {
      skip: false,
      eventType: 'f06_command',
      action: 'unblock_colleague',
      raw_action: 'unblock_colleague',
      discord_id,
      channel_id,
      content
    }}];
  }

  if (lower === 'meeting') {
    return [{ json: {
      skip: false,
      eventType: 'f06_command',
      action: 'unblock_meeting',
      raw_action: 'unblock_meeting',
      discord_id,
      channel_id,
      content
    }}];
  }

  if (lower === 'just-talk') {
    return [{ json: {
      skip: false,
      eventType: 'f06_command',
      action: 'unblock_just_talk',
      raw_action: 'unblock_just_talk',
      discord_id,
      channel_id,
      content
    }}];
  }

  if (lower === 'cancel') {
    return [{ json: { skip: true } }];
  }

  // Non-command plain text — may be a free-text reply for colleague_pending / meeting_pending
  if (content.length > 0) {
    return [{ json: {
      skip: false,
      eventType: 'f06_free_text',
      action: 'unblock_free_text',
      raw_action: 'unblock_free_text',
      discord_id,
      channel_id,
      content
    }}];
  }
}

return [{ json: { skip: true } }];

