const evt = $('Classify Event').first().json;
const draft = $('Lookup Draft').first().json;

// Block edit path for colleague_dm — approver is requester, edit would allow social-engineering text
if (draft.content_type === 'colleague_dm') {
  return [{ json: { skip: true } }];
}

// HIGH-01: verify the edit reply author is the approver
if (evt.actor_discord_id !== draft.approver_discord_id) {
  return [{ json: { skip: true } }];
}

// MED-03: sanitize content — strip n8n expression syntax, limit length
const safe = String(evt.content ?? '')
  .replace(/\{\{/g, '{ {')
  .replace(/\$\{/g, '$ {')
  .slice(0, 2000);

return [{ json: { skip: false, safe_content: safe, message_id: evt.message_id, reply_message_id: evt.reply_id, draft_id: draft.draft_id } }];

