const content = $('Classify Event').first().json.content ?? '';
const offerRow = $('Lookup Offer for Free Text').first().json;

// Match pattern: HH:MM-HH:MM (today|tomorrow)?
const match = content.match(/^(\d{1,2}):(\d{2})\s*[-–]\s*(\d{1,2}):(\d{2})(?:\s+(today|tomorrow))?/i);

if (!match) {
  return [{ json: {
    parse_ok: false,
    dm_channel_id: offerRow.dm_channel_id,
    offer_id: offerRow.offer_id
  }}];
}

const [, startH, startM, endH, endM, dayWord] = match;
const now = new Date();
const base = new Date(now.getFullYear(), now.getMonth(), now.getDate());

if (dayWord && dayWord.toLowerCase() === 'tomorrow') {
  base.setDate(base.getDate() + 1);
}

const start = new Date(base);
start.setHours(parseInt(startH, 10), parseInt(startM, 10), 0, 0);

const end = new Date(base);
end.setHours(parseInt(endH, 10), parseInt(endM, 10), 0, 0);

if (end <= start) {
  return [{ json: {
    parse_ok: false,
    dm_channel_id: offerRow.dm_channel_id,
    offer_id: offerRow.offer_id
  }}];
}

return [{ json: {
  parse_ok: true,
  start_iso: start.toISOString(),
  end_iso: end.toISOString(),
  start_label: startH.padStart(2,'0') + ':' + startM,
  end_label: endH.padStart(2,'0') + ':' + endM,
  dm_channel_id: offerRow.dm_channel_id,
  offer_id: offerRow.offer_id,
  feature_area: offerRow.feature_area,
  requester_calendar_email: offerRow.requester_calendar_email ?? ''
}}];

